import{c as e,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"SPLADE v2: Sparse Lexical and Expansion Model for Information Retrieval","description":"","frontmatter":{"title":"SPLADE v2: Sparse Lexical and Expansion Model for Information Retrieval","arxiv_id":2109.10086,"authors":"Thibault Formal, Carlos Lassance, Benjamin Piwowarski, Stéphane Clinchant","fetched":"2026-05-26T00:00:00.000Z","published":"2021-09-21T00:00:00.000Z","source":"https://arxiv.org/abs/2109.10086","source_tier":"P"},"headers":[],"relativePath":"research/papers/2021-09-21-splade-v2-sparse-lexical-expansion-2109-10086.md","filePath":"research/papers/2021-09-21-splade-v2-sparse-lexical-expansion-2109-10086.md","lastUpdated":1779901665000}'),i={name:"research/papers/2021-09-21-splade-v2-sparse-lexical-expansion-2109-10086.md"};function s(o,t,d,l,p,c){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="splade-v2-sparse-lexical-and-expansion-model-for-information-retrieval" tabindex="-1">SPLADE v2: Sparse Lexical and Expansion Model for Information Retrieval <a class="header-anchor" href="#splade-v2-sparse-lexical-and-expansion-model-for-information-retrieval" aria-label="Permalink to &quot;SPLADE v2: Sparse Lexical and Expansion Model for Information Retrieval&quot;">​</a></h1><p><strong>Authors</strong>: Thibault Formal (Naver Labs Europe / Sorbonne Université, LIP6), Carlos Lassance (Naver Labs Europe), Benjamin Piwowarski (Sorbonne Université, CNRS, LIP6), Stéphane Clinchant (Naver Labs Europe) <strong>Published</strong>: September 2021 <strong>Source</strong>: <a href="https://arxiv.org/abs/2109.10086" target="_blank" rel="noreferrer">https://arxiv.org/abs/2109.10086</a><strong>arXiv ID</strong>: 2109.10086 <strong>Categories</strong>: cs.IR, cs.AI, cs.CL <strong>Comments</strong>: 5 pages. Substantial text overlap with arXiv:2107.05720</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>In neural Information Retrieval (IR), ongoing research is directed towards improving the first retriever in ranking pipelines. Learning dense embeddings to conduct retrieval using efficient approximate nearest neighbors methods has proven to work well. Meanwhile, there has been a growing interest in learning <em>sparse</em> representations for documents and queries, that could inherit from the desirable properties of bag-of-words models such as the exact matching of terms and the efficiency of inverted indexes. Introduced recently, the SPLADE model provides highly sparse representations and competitive results with respect to state-of-the-art dense and sparse approaches. In this paper, we build on SPLADE and propose several significant improvements in terms of effectiveness and/or efficiency. More specifically, we modify the pooling mechanism, benchmark a model solely based on document expansion, and introduce models trained with distillation. We also report results on the BEIR benchmark. Overall, SPLADE is considerably improved with more than 9% gains on NDCG@10 on TREC DL 2019, leading to state-of-the-art results on the BEIR benchmark.</p><p><strong>Keywords</strong>: neural networks, indexing, sparse representations, regularization</p><hr><h2 id="core-thesis" tabindex="-1">Core Thesis <a class="header-anchor" href="#core-thesis" aria-label="Permalink to &quot;Core Thesis&quot;">​</a></h2><p>SPLADE&#39;s original sum-pooling mechanism is suboptimal; replacing it with max-pooling yields large effectiveness gains, a document-only encoder variant enables fully offline indexing with competitive quality, and cross-architecture knowledge distillation pushes DistilSPLADE-max to state-of-the-art zero-shot performance on BEIR while preserving the inverted-index efficiency of sparse retrieval.</p><hr><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><p>The release of large pre-trained language models like BERT (Devlin et al., 2018) transformed Information Retrieval. Neural rankers initially served as re-rankers in two-stage pipelines, where first-stage retrieval relied on bag-of-words (BM25) models using inverted indexes. While BOW models remain strong baselines, they suffer from the vocabulary mismatch problem, where relevant documents may not contain exact query terms.</p><p>Dense retrieval with approximate nearest neighbors has shown impressive results, but can still benefit from BOW approaches due to the absence of explicit term matching. This motivates learning <strong>sparse</strong> representations for queries and documents — inheriting exact-match properties and inverted-index efficiency, while also modeling implicit expansion to reduce vocabulary mismatch.</p><p>This paper builds on the original SPLADE model (Formal et al., 2021) with three main contributions:</p><ol><li><strong>Max pooling</strong>: Replacing sum pooling with max pooling substantially increases effectiveness.</li><li><strong>Document-only encoder (SPLADE-doc)</strong>: A model without query expansion where everything can be pre-computed and indexed offline — more efficient with competitive results.</li><li><strong>Distillation (DistilSPLADE-max)</strong>: Two-step distillation training leading to close to state-of-the-art on MS MARCO and BEIR.</li></ol><hr><h2 id="_2-related-works" tabindex="-1">2. Related Works <a class="header-anchor" href="#_2-related-works" aria-label="Permalink to &quot;2. Related Works&quot;">​</a></h2><p><strong>Dense retrieval</strong>: BERT Siamese models (Sentence-BERT) are standard for candidate generation in QA and IR. Key training improvements include better negative sampling and distillation. ColBERT extends this with token-level interactions for fine-grained matching, at the cost of large embedding storage.</p><p><strong>Sparse retrieval history</strong>:</p><ul><li><strong>SNRM</strong> (Zamani et al., 2018): First sparse high-dimensional latent space via ℓ₁ regularization; limited effectiveness and efficiency.</li><li><strong>DeepCT</strong> (Dai &amp; Callan, 2019): Contextualized term weight learning within the fixed document vocabulary — does not solve vocabulary mismatch.</li><li><strong>doc2query / docTTTTTquery</strong> (Nogueira et al.): Generative document expansion to predict query terms, adding new terms and boosting important ones.</li><li><strong>DeepImpact</strong> (Mallia et al., 2021): Combines doc2query-T5 expansion with DeepCT reweighting to learn term impacts.</li><li><strong>SparTerm, EPIC, SPARTA</strong>: Compute interaction matrices between document/query tokens and full vocabulary, then aggregate. EPIC and SPARTA lack sufficient sparsity; SparTerm lacks explicit sparsity regularization.</li><li><strong>SPLADE</strong> (Formal et al., 2021): Combines regularization (FLOPS), expansion, and compression in an end-to-end manner.</li><li><strong>COIL</strong> (Gao et al., 2021): Dense per-term representations for contextualized term matching; larger index size.</li></ul><hr><h2 id="_3-sparse-lexical-representations-for-first-stage-ranking" tabindex="-1">3. Sparse Lexical Representations for First-Stage Ranking <a class="header-anchor" href="#_3-sparse-lexical-representations-for-first-stage-ranking" aria-label="Permalink to &quot;3. Sparse Lexical Representations for First-Stage Ranking&quot;">​</a></h2><h3 id="_3-1-splade-model" tabindex="-1">3.1 SPLADE Model <a class="header-anchor" href="#_3-1-splade-model" aria-label="Permalink to &quot;3.1 SPLADE Model&quot;">​</a></h3><p>SPLADE predicts term importance across the BERT WordPiece vocabulary (|V| = 30,522) using the MLM layer logits. For input sequence t = (t₁, t₂, ..., t_N) with BERT embeddings (h₁, h₂, ..., h_N):</p><p><strong>Token-vocabulary importance weight</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>w_ij = transform(h_i)^T E_j + b_j    j ∈ {1,...,|V|}</span></span></code></pre></div><p>where E_j is the BERT input embedding for token j, b_j is a token-level bias, and transform(·) is a linear layer with GeLU activation and LayerNorm.</p><p><strong>Final representation (original sum pooling)</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>w_j = Σ_{i∈t} log(1 + ReLU(w_ij))</span></span></code></pre></div><p><strong>Ranking loss</strong> (contrastive with in-batch negatives):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ℒ_{rank-IBN} = -log [ e^{s(q_i, d_i+)} / (e^{s(q_i, d_i+)} + e^{s(q_i, d_i-)} + Σ_j e^{s(q_i, d_{i,j}-})) ]</span></span></code></pre></div><p><strong>FLOPS regularization</strong> (Paria et al., 2020): Penalizes the expected number of floating-point operations needed for retrieval:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ℓ_FLOPS = Σ_{j∈V} ā_j² = Σ_{j∈V} (1/N · Σ_{i=1}^N w_j^{(d_i)})²</span></span></code></pre></div><p><strong>Overall loss</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ℒ = ℒ_{rank-IBN} + λ_q · ℒ_reg^q + λ_d · ℒ_reg^d</span></span></code></pre></div><p>Separate regularization weights for queries and documents allow stronger sparsity pressure on queries (critical for fast retrieval).</p><h3 id="_3-2-pooling-strategy-splade-max" tabindex="-1">3.2 Pooling Strategy (SPLADE-max) <a class="header-anchor" href="#_3-2-pooling-strategy-splade-max" aria-label="Permalink to &quot;3.2 Pooling Strategy (SPLADE-max)&quot;">​</a></h3><p>Replace sum pooling with <strong>max pooling</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>w_j = max_{i∈t} log(1 + ReLU(w_ij))</span></span></code></pre></div><p>This makes the model more similar to SPARTA/EPIC/ColBERT. Max pooling is now the default and the model is called <strong>SPLADE-max</strong>.</p><h3 id="_3-3-splade-document-encoder-splade-doc" tabindex="-1">3.3 SPLADE Document Encoder (SPLADE-doc) <a class="header-anchor" href="#_3-3-splade-document-encoder-splade-doc" aria-label="Permalink to &quot;3.3 SPLADE Document Encoder (SPLADE-doc)&quot;">​</a></h3><p>A document-only version with no query expansion. The ranking score is:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>s(q, d) = Σ_{j∈q} w_j^d</span></span></code></pre></div><p>Since the score only depends on document term weights, everything can be <strong>pre-computed and indexed offline</strong>, reducing online inference cost. Simpler to train — only a single forward pass per document (vs. multiple beam search inferences for doc2query-T5).</p><h3 id="_3-4-distillation-and-hard-negatives-distilsplade-max" tabindex="-1">3.4 Distillation and Hard Negatives (DistilSPLADE-max) <a class="header-anchor" href="#_3-4-distillation-and-hard-negatives-distilsplade-max" aria-label="Permalink to &quot;3.4 Distillation and Hard Negatives (DistilSPLADE-max)&quot;">​</a></h3><p>Two-step distillation process:</p><ol><li>Train a SPLADE first-stage retriever and a cross-encoder reranker (using <code>cross-encoder/ms-marco-MiniLM-L-12-v2</code>) on triplets from Hofstätter et al. (2020).</li><li>Generate harder negative triplets using the distillation-trained SPLADE, then use the reranker to produce Margin-MSE loss scores. Train a new SPLADE model from scratch on these triplets.</li></ol><hr><h2 id="_4-experimental-setting-and-results" tabindex="-1">4. Experimental Setting and Results <a class="header-anchor" href="#_4-experimental-setting-and-results" aria-label="Permalink to &quot;4. Experimental Setting and Results&quot;">​</a></h2><p><strong>Dataset</strong>: MS MARCO passage ranking (≈8.8M passages; dev set: 6,980 queries; TREC DL 2019: 43 queries with fine-grained annotations).</p><p><strong>Training setup</strong>:</p><ul><li>Initialized from DistilBERT-base checkpoint</li><li>ADAM optimizer, lr = 2e-5, linear scheduling, warmup = 6,000 steps, batch size = 124</li><li>Max sequence length: 256</li><li>λ scheduler: quadratically increases until 50k steps, then constant; typical values 1e-1 to 1e-4</li><li>Separate λ for queries and documents</li><li>Best checkpoint by MRR@10 on 500-query validation set after 150k iterations (SPLADE-doc: 50k steps, last checkpoint)</li><li>Infrastructure: 4× Tesla V100 32GB; PyTorch + HuggingFace Transformers</li><li>Custom index with Python arrays + Numba for parallel retrieval</li></ul><p><strong>Evaluation metrics</strong>: MRR@10 (MS MARCO dev), NDCG@10 and Recall@1000 (both MS MARCO dev and TREC DL 2019).</p><h3 id="table-1-ms-marco-dev-and-trec-dl-2019-results" tabindex="-1">Table 1: MS MARCO Dev and TREC DL 2019 Results <a class="header-anchor" href="#table-1-ms-marco-dev-and-trec-dl-2019-results" aria-label="Permalink to &quot;Table 1: MS MARCO Dev and TREC DL 2019 Results&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>MRR@10</th><th>R@1000</th><th>NDCG@10</th><th>R@1000 (TREC)</th></tr></thead><tbody><tr><td><strong>Dense Retrieval</strong></td><td></td><td></td><td></td><td></td></tr><tr><td>Siamese (ours)</td><td>0.312</td><td>0.941</td><td>0.637</td><td>0.711</td></tr><tr><td>ANCE</td><td>0.330</td><td>0.959</td><td>0.648</td><td>—</td></tr><tr><td>TCT-ColBERT</td><td>0.359</td><td>0.970</td><td>0.719</td><td>0.760</td></tr><tr><td>TAS-B</td><td>0.347</td><td>0.978</td><td>0.717</td><td>0.843</td></tr><tr><td>RocketQA</td><td>0.370</td><td>0.979</td><td>—</td><td>—</td></tr><tr><td><strong>Sparse Retrieval</strong></td><td></td><td></td><td></td><td></td></tr><tr><td>BM25</td><td>0.184</td><td>0.853</td><td>0.506</td><td>0.745</td></tr><tr><td>DeepCT</td><td>0.243</td><td>0.913</td><td>0.551</td><td>0.756</td></tr><tr><td>doc2query-T5</td><td>0.277</td><td>0.947</td><td>0.642</td><td>0.827</td></tr><tr><td>SparTerm</td><td>0.279</td><td>0.925</td><td>—</td><td>—</td></tr><tr><td>COIL-tok</td><td>0.341</td><td>0.949</td><td>0.660</td><td>—</td></tr><tr><td>DeepImpact</td><td>0.326</td><td>0.948</td><td>0.695</td><td>—</td></tr><tr><td>SPLADE (Formal et al., 2021)</td><td>0.322</td><td>0.955</td><td>0.665</td><td>0.813</td></tr><tr><td><strong>Our Methods</strong></td><td></td><td></td><td></td><td></td></tr><tr><td>SPLADE-max</td><td>0.340</td><td>0.965</td><td>0.684</td><td>0.851</td></tr><tr><td>SPLADE-doc</td><td>0.322</td><td>0.946</td><td>0.667</td><td>0.747</td></tr><tr><td><strong>DistilSPLADE-max</strong></td><td><strong>0.368</strong></td><td><strong>0.979</strong></td><td><strong>0.729</strong></td><td><strong>0.865</strong></td></tr></tbody></table><h3 id="_4-1-impact-of-max-pooling" tabindex="-1">4.1 Impact of Max Pooling <a class="header-anchor" href="#_4-1-impact-of-max-pooling" aria-label="Permalink to &quot;4.1 Impact of Max Pooling&quot;">​</a></h3><p>Max pooling brings ~2 points improvement in MRR@10 and NDCG@10 over the SPLADE sum-pooling baseline. SPLADE-max is consistently better than original SPLADE across the full effectiveness-efficiency trade-off curve (FLOPS). Also improves on BEIR.</p><h3 id="_4-2-document-expansion-splade-doc" tabindex="-1">4.2 Document Expansion (SPLADE-doc) <a class="header-anchor" href="#_4-2-document-expansion-splade-doc" aria-label="Permalink to &quot;4.2 Document Expansion (SPLADE-doc)&quot;">​</a></h3><p>The document-only encoder reaches the same performance as original SPLADE, outperforming doc2query-T5 on MS MARCO. For relatively sparse representations (avg. 19 non-zero weights/doc), achieves MRR@10 = 29.6. Training and application is simpler: single forward pass vs. multiple beam search inferences.</p><h3 id="_4-3-distillation" tabindex="-1">4.3 Distillation <a class="header-anchor" href="#_4-3-distillation" aria-label="Permalink to &quot;4.3 Distillation&quot;">​</a></h3><p>DistilSPLADE-max achieves large improvements, especially in higher FLOPS regimes (0.368 MRR@10 at ≈4 FLOPS) while remaining efficient at low FLOPS (0.35 MRR at ≈0.3 FLOPS).</p><h3 id="table-2-beir-benchmark-results-ndcg-10" tabindex="-1">Table 2: BEIR Benchmark Results (NDCG@10) <a class="header-anchor" href="#table-2-beir-benchmark-results-ndcg-10" aria-label="Permalink to &quot;Table 2: BEIR Benchmark Results (NDCG@10)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Corpus</th><th>ColBERT</th><th>BM25</th><th>TAS-B</th><th>SPLADE-sum</th><th>SPLADE-max</th><th>DistilSPLADE-max</th></tr></thead><tbody><tr><td>MS MARCO</td><td>0.425</td><td>0.228</td><td>0.408</td><td>0.387</td><td>0.402</td><td>0.433</td></tr><tr><td>ArguAna</td><td>0.233</td><td>0.315</td><td>0.427</td><td>0.447</td><td>0.439</td><td><strong>0.479</strong></td></tr><tr><td>Climate-FEVER</td><td>0.184</td><td>0.213</td><td>0.228</td><td>0.162</td><td>0.199</td><td><strong>0.235</strong></td></tr><tr><td>DBPedia</td><td>0.392</td><td>0.273</td><td>0.384</td><td>0.343</td><td>0.366</td><td><strong>0.435</strong></td></tr><tr><td>FEVER</td><td>0.771</td><td>0.753</td><td>0.700</td><td>0.728</td><td>0.730</td><td><strong>0.786</strong></td></tr><tr><td>FiQA-2018</td><td>0.317</td><td>0.236</td><td>0.300</td><td>0.258</td><td>0.287</td><td><strong>0.336</strong></td></tr><tr><td>HotpotQA</td><td>0.593</td><td>0.603</td><td>0.584</td><td>0.635</td><td>0.636</td><td><strong>0.684</strong></td></tr><tr><td>NFCorpus</td><td>0.305</td><td><strong>0.325</strong></td><td>0.319</td><td>0.311</td><td>0.313</td><td>0.334</td></tr><tr><td>NQ</td><td>0.524</td><td>0.329</td><td>0.463</td><td>0.438</td><td>0.469</td><td><strong>0.521</strong></td></tr><tr><td>Quora</td><td><strong>0.854</strong></td><td>0.789</td><td>0.835</td><td>0.829</td><td>0.835</td><td>0.838</td></tr><tr><td>SCIDOCS</td><td>0.145</td><td><strong>0.158</strong></td><td>0.149</td><td>0.141</td><td>0.145</td><td><strong>0.158</strong></td></tr><tr><td>SciFact</td><td>0.671</td><td>0.665</td><td>0.643</td><td>0.626</td><td>0.628</td><td><strong>0.693</strong></td></tr><tr><td>TREC-COVID</td><td>0.677</td><td>0.656</td><td>0.481</td><td>0.655</td><td>0.673</td><td><strong>0.710</strong></td></tr><tr><td>Touché-2020 (v1)</td><td>0.275</td><td><strong>0.614</strong></td><td>0.173</td><td>0.289</td><td>0.316</td><td>0.364</td></tr><tr><td><strong>Avg. all</strong></td><td>0.455</td><td>0.440</td><td>0.435</td><td>0.446</td><td>0.460</td><td><strong>0.500</strong></td></tr><tr><td><strong>Avg. zero-shot</strong></td><td>0.457</td><td>0.456</td><td>0.437</td><td>0.451</td><td>0.464</td><td><strong>0.506</strong></td></tr><tr><td><strong>Best on dataset</strong></td><td>2</td><td>2</td><td>0</td><td>0</td><td>0</td><td><strong>11</strong></td></tr></tbody></table><p>DistilSPLADE-max wins on 11 of 14 datasets, achieving best average scores on both all and zero-shot subsets.</p><hr><h2 id="_5-conclusion" tabindex="-1">5. Conclusion <a class="header-anchor" href="#_5-conclusion" aria-label="Permalink to &quot;5. Conclusion&quot;">​</a></h2><p>Three improvements to SPLADE:</p><ol><li><strong>Max pooling</strong> provides substantial effectiveness gains over sum pooling.</li><li><strong>SPLADE-doc</strong> (document-only encoder) enables fully offline indexing with competitive quality — good for latency-constrained settings.</li><li><strong>DistilSPLADE-max</strong> (two-step knowledge distillation) leads to near state-of-the-art on MS MARCO/TREC DL 2019 and clearly outperforms recent dense models on zero-shot BEIR evaluation.</li></ol><p>Key result: DistilSPLADE-max achieves 0.368 MRR@10 on MS MARCO dev, 0.729 NDCG@10 on TREC DL 2019, and 0.500 avg NDCG@10 on BEIR (beating ColBERT&#39;s 0.455), while maintaining inverted-index efficiency.</p><hr><h2 id="key-references" tabindex="-1">Key References <a class="header-anchor" href="#key-references" aria-label="Permalink to &quot;Key References&quot;">​</a></h2><ul><li><strong>Formal et al. (2021)</strong> — SPLADE: Sparse Lexical and Expansion Model for First Stage Ranking. SIGIR &#39;21. <a href="https://doi.org/10.1145/3404835.3463098" target="_blank" rel="noreferrer">https://doi.org/10.1145/3404835.3463098</a></li><li><strong>Hofstätter et al. (2021)</strong> — TAS-B: Efficiently Teaching an Effective Dense Retriever with Balanced Topic Aware Sampling. SIGIR 2021.</li><li><strong>Hofstätter et al. (2020)</strong> — Improving Efficient Neural Ranking Models with Cross-Architecture Knowledge Distillation. arXiv:2010.02666</li><li><strong>Thakur et al. (2021)</strong> — BEIR: A Heterogeneous Benchmark for Zero-shot Evaluation of IR Models. arXiv:2104.08663</li><li><strong>Paria et al. (2020)</strong> — Minimizing FLOPs to Learn Efficient Sparse Representations. arXiv:2004.05665</li><li><strong>Mallia et al. (2021)</strong> — DeepImpact: Learning Passage Impacts for Inverted Indexes. SIGIR &#39;21.</li><li><strong>Gao et al. (2021)</strong> — COIL: Revisit Exact Lexical Match in IR with Contextualized Inverted List. NAACL 2021.</li><li><strong>Khattab &amp; Zaharia (2020)</strong> — ColBERT: Efficient and Effective Passage Search via Contextualized Late Interaction over BERT. SIGIR &#39;20.</li><li><strong>Xiong et al. (2021)</strong> — ANCE: Approximate Nearest Neighbor Negative Contrastive Learning for Dense Text Retrieval. ICLR 2021.</li><li><strong>Lin et al. (2021)</strong> — TCT-ColBERT: In-Batch Negatives for Knowledge Distillation with Tightly-Coupled Teachers. RepL4NLP 2021.</li><li><strong>Dai &amp; Callan (2019)</strong> — DeepCT: Context-Aware Sentence/Passage Term Importance Estimation. arXiv:1910.10687</li><li><strong>Nogueira &amp; Lin (2019)</strong> — From doc2query to docTTTTTquery.</li><li><strong>Bai et al. (2020)</strong> — SparTerm: Learning Term-based Sparse Representation for Fast Text Retrieval. arXiv:2010.00768</li><li><strong>Zamani et al. (2018)</strong> — SNRM: From Neural Re-Ranking to Neural Ranking. CIKM &#39;18.</li><li><strong>Devlin et al. (2018)</strong> — BERT: Pre-training of Deep Bidirectional Transformers. arXiv:1810.04805</li></ul>',72)])])}const m=e(i,[["render",s]]);export{h as __pageData,m as default};
